<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Add') }} {{ $t('Project') }} {{ $t('Request') }} {{ $t('Owner') }}</h4>      
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">                      
                        <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 searchpanel tablehead search float-left p-0">
                            <div class="col-sm-12 col-md-12 col-lg-12 col-xl-12 Search-panel float-left pb-3 p-0">
                                <div class="col-sm-12 col-md-12 col-lg-6 col-xl-6 float-left">
                                    <div class="row mt-0">
                                        <div class="col-6 col-sm-6 col-md-6 col-lg-6 col-xl-6 float-left pr-1 pl-0">
                                            <div class="form-group">
                                                <input id="txtTeamSearchPop" @keyup="SearchTeam_Add" v-model="SearchProjectTeam" class="form-control" type="text" :placeholder="$t('SearchByusername')" />
                                            </div>
                                        </div>
                                        <div class="col-6 col-sm-6 col-md-6 col-lg-6 col-xl-6 float-left pl-0">
                                            <div class="background-0 text-left form-check-inline">
                                                <a title="Clear" @click="clearTeam_add" href="javascript:;" class="btn btn-danger clearsearchtext px-4"><i class="fa fa-refresh"></i></a>
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                        <div class="listing">
                            <div class="table-responsive tableFixHead float-left" id="divmemb">
                                <table id="mainTable" class="table table-bordered dt-responsive nowrap mt-0">
                                    <thead class="thead-bg">
                                        <tr>                                            
                                            <th style="width:50px !important;" class="text-center">
                                                    <div class="custom-control custom-checkbox">
                                                        <input class="chkItems setcheckall custom-control-input"
                                                            type="checkbox" id="chkAll" name="checkbox" 
                                                            style="display: none;" v-on:change="SelectAllChekcboxes($event)">
                                                        <label
                                                            class="custom-control-label universal-custom-control-label pt-1"
                                                            for="chkAll"></label>
                                                    </div>
                                            </th>
                                            <th>
                                                <span> {{ $t('UserName') }}</span>
                                            </th>
                                            <th>
                                                <span> {{ $t('Department') }}</span>
                                            </th>
                                            <th>
                                                <span>{{ $t('Designation') }}</span>
                                            </th>
                                        </tr>
                                    </thead>
                                    <tbody>
                                        <tr>
                                            <td colspan="4" class="text-center text-danger no-record" v-if="ProjectRequestOwnerData.length==0">
                                                {{ $t('NoRecordfound') }}
                                            </td>
                                        </tr> 
                                        <tr v-for="(item,index) in ProjectRequestOwnerData" :key="index">
                                            <td style="width:50px !important;" class="text-center align-middle">
                                                <div class="custom-control custom-checkbox">
                                                        <input type="checkbox" :value="item.PROJECTREQUESTOWNERID" v-on:change="checkboxidds($event,item)"  class="custom-control-input addmem checkboxid" :id="'checkboxid'+item.PROJECTREQUESTOWNERID"   v-bind:name="'chk_'+item.PROJECTREQUESTOWNERID" style="display: none;">
                                                        <label class="custom-control-label universal-custom-control-label pt-1" :for="'checkboxid'+item.PROJECTREQUESTOWNERID"></label>
                                                </div>                                                
                                            </td>
                                            <td class="align-middle">
                                                {{ item.PROJECTREQUESTOWNERNAME  || "-" }}
                                            </td>
                                            <td class="align-middle">
                                                {{ item.DEPARTMENT || "-" }}
                                            </td>
                                            <td class="align-middle">
                                                {{ item.DESIGNATION || "-" }}
                                            </td>
                                           
                                        </tr>
                                    </tbody>
                                </table>
                            </div>
                        </div>
                        <div class="clearfix"></div>
                        <div class="row flex-row-reverse mt-2">
                            <div class="col-lg-6 text-right">                                
                                <a v-if="ProjectRequestOwnerData.length>0" class="btn btn-success formbtn widthhalf mr-2" title="Save" @click="ancAddEditTeamMembers"><i class="fa fa-save pr-2"></i>{{ $t('Save') }}</a>                              
                                <a v-on:click="Close" class="btn btn-danger formbtn widthhalf" title="Cancel" id="ancAddTeamCancel"><i class="fa fa-close pr-2"></i>{{ $t('Cancel') }}</a>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService';
export default{
    data(){
        return{
            isLoading:false,
            SearchProjectTeam:'',
            selectedOwners:[],
            ProjectRequestOwnerData:[]
        }
    },
    created:function(){
        this.GetUsersList();
    },   
    methods:{
        clearTeam_add:function(){
            this.SearchProjectTeam='';
            this.GetUsersList();
        },
        SearchTeam_Add() {
            var filteredTeamData=[];
            const query = this.SearchProjectTeam.toLowerCase();
            filteredTeamData = this.ProjectRequestOwnerData.filter(item =>
                item.PROJECTREQUESTOWNERNAME.toLowerCase().includes(query)
            );            
            this.ProjectRequestOwnerData=[];
            this.ProjectRequestOwnerData=filteredTeamData;
        },
        ancAddEditTeamMembers:function(){
            debugger
            var vm = this;           
            var val = this.selectedOwners.join(',');  
            if(val ==''){
                vm.ShowAlert("Please select at least one user to add.", "failure", true, "Alert");
                return false;
            }      
            var url=`userIds=${val}`;
            DataService.AddProjectRequestOwner(url).then(function (response) {  
                    if(response.data.result[0].Value==0){
                        vm.ShowAlert(vm.$t('ProjectRequestOwnerAddedSuccessfully'), "success", true, "Alert");
                        vm.Close();
                        vm.$parent.FetchData();                       
                    }else{
                        vm.ShowAlert("Please select at least one user to add.", "failure", true, "Alert");
                    }
            });
          
        },
        checkboxidds(evt,item){ 
           var vm = this;
           if(evt.target.checked){
                this.selectedOwners.push(item.PROJECTREQUESTOWNERID)             
           }else{
                this.selectedOwners=[];
           }       
        },
        SelectAllChekcboxes(evt){
            var checkedarray = document.getElementsByClassName("custom-control-input addmem checkboxid");
            if(evt.target.checked){
                for (var i = 0; i < checkedarray.length; i++) {                    
                    this.selectedOwners = this.ProjectRequestOwnerData.map(item => item.PROJECTREQUESTOWNERID);
                    checkedarray[i].checked = true;
                }
            }else{
                for (var i = 0; i < checkedarray.length; i++) {
                    checkedarray[i].checked = false;                    
                    this.selectedOwners=[];
                }
            }
        },
        GetUsersList:function(){
            DataService.GetUsersList().then((response)=>{
                if(response.data.result.length>0){
                    this.ProjectRequestOwnerData=response.data.result;
                }
            })
        },
        Close:function(){
            this.$parent.isProjectRequest=false;
        }
    }
}
</script>