<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('Comments') }} </h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form :buttons="buttons" :schema="FormSchema" ref="AcceptRejectForm" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="OnSubmit">
                        </dynamic-form>
                        <div class="clearfix"></div>
                        <div class="listing tab-content mt-2" id="divconversationbox" v-if="CommentData.length>0">
                            <div class="col-12 d-flex border border-bottom-0 bg-f5f5f5">
                                <div class="col-md-6 pl-0">
                                    <h6 class="py-3 mb-0">
                                        {{ $t('Comments') }}
                                    </h6>
                                </div>
                                <div class="col-md-6 text-right pr-0 bottom_filter_button">
                                    <a @click="togglePanels" id="ancreplyExpandAllCollapseAll" class="position-relative" style="z-index:999;" :title="$t('ExpandAllCollapseAll')" data-toggle-tooltip="tooltip">{{ $t('ExpandAllCollapseAll') }}</a>
                                </div>
                            </div>
                            <div class="card" v-for="(item, parentIndex) in CommentData" :index="parentIndex">                              
                                <div class="card-header">
                                    <a class="card-link collapsed" :href="'#Expensecollapse' + parentIndex" @click.prevent="togglePanel(parentIndex)">
                                        <div class="conversation-date heading-border">
                                            <span><em class="pr-1" aria-hidden="true"></em>{{item.groupKey}}</span>
                                        </div>
                                    </a>
                                </div>
                                <div v-bind:id="'Expensecollapse'+parentIndex" v-bind:class="{'collapse':true, 'show':parentIndex==0}" :class="{'collapse': true, 'show': item.isOpen}">
                                    <div class="card-body" v-for="(childItem, childIndex) in item.groupData" :key="childIndex">
                                        <div class="conversation-main">                                                            
                                            <div class="conversation-time"><span>{{$options.filters.formatTime(childItem.CREATEDAT)}}</span></div>
                                            <div class="conversation-box-con">
                                                <div class="conversation-box">
                                                    <div class="name-circle light-yellow">                                                                       
                                                        <!-- <img class="img-circle avatar" :src="blobUrl" width="51" height="51" alt="Image" /> -->
                                                         <span class="mt-2">
                                                            {{ getInitials(childItem.POSTEDBYNAME ) }}
                                                         </span>
                                                    </div>
                                                    <div class="conversation-header addednote-ticket">
                                                        <span>
                                                            <span class="sender-name">{{ childItem.NOTES }}</span>                                                       
                                                        </span>
                                                    </div>                                                    
                                                    <div class="conversation-content">
                                                        <div class="col-12 p-0 notesdata">
                                                            <h6 class="text-muted time">
                                                                <i>
                                                                    <b>{{ childItem.POSTEDBYNAME }}</b>, {{ $t('PostedOn') }}: <span class="text-danger">
                                                                      {{ $options.filters.formatTime(childItem.CREATEDAT) }}  {{TimeAgo(childItem.CREATEDAT)}}
                                                                    </span>
                                                                </i>
                                                            </h6>                                                           
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>
                                        </div>                                                 
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import moment from 'moment';
import DataService from '../../services/DataService';
export default{
    props:{
        AcceptRejectData:{
            type:Object,
            required:true
        }
    },
    data(){
       return{
        isLoading:false,
        CommentData:[],
        blobUrl:'',
       
        MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
        FormSchema: [  
                {
                    layoutType: "single",
                    group_name:'Post New Comment',
                    Data: [
                        {
                            astype: "TextAreaField",                 
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",  
                            validationRules: { "required": true, max: 4000 },
                            config: {
                                rows:3
                            }
                        }
                    ]
                }
        ],
        buttons: [
            {
                type: "submit",
                class: "btn btn-info",
                text: "<i class='fa fa-send pr-2'></i>Post New Comment",                                   
            }
        ],
        Issave:true,
       }
    },
    created: function(){  
        var ths = this;
        ths.AddProjectRequestNotes();
        ths.GetBlobUrl();
    },
    methods:{
        TimeAgo:function(value){            
            if (value) {
                const timestamp = moment(value);       
                const formatted = timestamp.format('MM/DD/YYYY');
                 return formatted;
                // const now = moment();
                // const yearsAgo = now.diff(timestamp, 'years');
                // const monthsAgo = now.diff(timestamp, 'months');
                // const daysAgo = now.diff(timestamp, 'days');
                // const hoursAgo = now.diff(timestamp, 'hours');
                // const minutesAgo = now.diff(timestamp, 'minutes');
                // const secondsAgo = now.diff(timestamp, 'seconds');
              
                // if (yearsAgo > 0) {
                //     return `${yearsAgo} year(s) ago`;
                // } else if (monthsAgo > 0) {
                //     return `${monthsAgo}`;
                // } else if (daysAgo > 0) {
                //     return `${daysAgo} `;
                // } else if (hoursAgo > 0) {
                //     return `${hoursAgo} `;
                // } else if (minutesAgo > 0) {
                //     return `${minutesAgo}`;
                // } else {
                //     return `${secondsAgo} `;
                // }
            }
        },
        togglePanels() {            
            const anyOpen = this.CommentData.some(item => item.isOpen);
            this.CommentData.forEach(item => {item.isOpen = !anyOpen; });
        },
        togglePanel(index) {
            this.CommentData[index].isOpen = !this.CommentData[index].isOpen; 
        },
        GetBlobUrl: function () {
            DataService.GetBlobUrl().then((response) => { 
                var url = response.data[0].CONFIG_DATA_VALUE;
                if(this.avatar==null){
                    this.blobUrl = '/Content/images/DefaultImages/uc_user_new.jpg';
                }
                else{
                    this.blobUrl = url + '/' + this.containerName + '/' + 'Upload' + '/' + 'UserProfileImage' + '/' + this.avatar
                } 
            })
        }, 
        AddProjectRequestNotes:function(){
            var ths=this;
            var url =`Prid=${ths.AcceptRejectData.Prid}`;
            DataService.AddProjectRequestNotes(url).then(function (response) {                 
                if(response.data.result.length>0){                    
                    var fullJSON=response.data.result;
                    ths.CommentData = [];
                    var gruopBy = "";
                    $.each(fullJSON,$.proxy(function(index,item){                        
                        gruopBy=ths.$options.filters.formatDate(item.CREATEDAT);
                        var chkGroup = $.grep(ths.CommentData, function (element, index) {                            
                            return element.groupKey == gruopBy;
                            }
                        );
                        if (chkGroup.length == 0) {
                            var returnedData = $.grep(fullJSON,function (element, index) {                                
                                return ths.$options.filters.formatDate(element.CREATEDAT) == gruopBy;
                              }
                         );
                        if (returnedData.length > 0) {
                            var objGroup = {
                              groupKey: gruopBy,
                              isOpen: false ,
                              groupData: returnedData,
                            };
                            ths.CommentData.push(objGroup);                           
                            ths.avatar=ths.CommentData[0].groupData[0].avatar;                            
                        }
                    }
                    },this)); 
                }else{
                    ths.CommentData = [];
                }
            })
        },
        OnSubmit:function(){ 
            var vm=this;
            if(vm.Issave)
        {
            vm.Issave=false;
            var data = {
                Prid:vm.AcceptRejectData.Prid,
                type:vm.AcceptRejectData.type,
                createdby:vm.AcceptRejectData.createdby,
                prtitle:vm.AcceptRejectData.ProjectTitle,
                createdbyname:vm.AcceptRejectData.createdbyname,
                notes:vm.FormSchema[0].Data[0].value
            } 
            vm.isLoading = true; 
            var objectPostString = JSON.stringify(data); 
            DataService.SaveProjectRequestNotes(objectPostString).then(function (response) { 
                vm.isLoading = false;
                if(response.data.response=='success'){
                    vm.ShowAlert(vm.$t("CommentHasBeenPostedSuccessfully"),"success",true,vm.$t("Alert"));
                    vm.AddProjectRequestNotes();
                }else{
                    vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"),"failure",true,vm.$t("Alert"));
                }
                vm.Issave=true;                
            });
        }
        },
        getInitials(name) {
            if (!name) return '??';
            return name
                .split(' ')
                .map(word => word[0])
                .join('')
                .toUpperCase();
        },
        Close:function(){
            this.$parent.IsProjectNotes=false;
        }
    }
}
</script>