<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list ref="tgList" :listType="['List']" :IsShowAction="true" :showCheckBox="true" ModuleName="PROJECT"
            SubModuleCode="ProjectRequest" IdentityColumn="PROJECT_REQUEST_ID" :HeaderText="$t('ProjectRequest')"
            :ListData="RequestData" :HeaderData="Headers" :widgets="widgets" :HeaderButtons="listheaderbuttons"
            :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" :RenderRowActionMethod="renderActions"
            :ListDataCallBackFunction="FetchData" :SortExp="SortExp" :SortBy="SortBy" :LegendArray="LegendArray"
            :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
            v-on:ActionButtonClick="actionButtonClick" v-on:SortdataButtonClick="sortdata" :Key="Key">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'DESCRIPTION'">
                    <span>{{ TruncateStr(removeHtmlTags(data.row.DESCRIPTION), 30) }}</span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'TITLE'">
                    <RouterLink :to="'Details/' + data.row.PROJECT_REQUEST_ID"
                        @click="RequestDetails(data.row.PROJECT_REQUEST_ID)">{{ TruncateStr(data.row.TITLE, 20) }}
                    </RouterLink>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'STATUS_NAME'">
                    <span v-if="data.row.STATUS_CODE == 'PRO_REQ_ACCEPTED'"
                        class="sent px-2 bg-info text-white d-block text-center">{{ data.row.STATUS_NAME }} </span>
                    <span v-else-if="data.row.STATUS_CODE == 'PRO_REQ_REJECTED'"
                        class="stop px-2 bg-danger text-white d-block text-center">{{ data.row.STATUS_NAME }} </span>
                    <span v-else-if="data.row.STATUS_CODE == 'PRO_REQ_CONVERTED'"
                        class="generated px-2 bg-warning text-white d-block text-center">{{ data.row.STATUS_NAME }}
                    </span>
                    <span v-else class="fullPaid px-2 bg-success text-white d-block text-center">{{ data.row.STATUS_NAME
                        }} </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'BUDGET'">
                    <span>{{ $n(data.row.BUDGET, 'currency', $getLocaleByCurrency(CurrencyCode)) }} </span>
                </template>
            </template>
        </tg-list>
        <div class="my-popups" v-if="isShowConvertProject">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title"> {{ $t('Project') }}</h4>

                        <button type="button" class="close" v-on:click="CloseProjectConvert">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" ref="ConvertProject" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="OnSubmit"></dynamic-form>
                    </div>   
                </div>
            </div>
        </div>
    </div>
        <ProjectRequestOwner v-if="isProjectRequest"></ProjectRequestOwner>
        <ProjectAcceptReject v-if="IsProjectAccpt" :AcceptRejectData="AcceptRejectData" @CloseProjectAccptReject="CloseProjectAccptReject"></ProjectAcceptReject>
        <RejectProjectRequest v-if="IsProjectReject" :AcceptRejectData="AcceptRejectData" @CloseProjectReject="CloseProjectReject"></RejectProjectRequest>
        <ProjectRequestNotes v-if="IsProjectNotes" :AcceptRejectData="AcceptRejectData" @CloseProjectReject="CloseProjectReject"></ProjectRequestNotes>
    </section>
</template>
<script>
import DataService from '../../../services/DataService';
import ProjectRequestOwner from '../../../components/Modal/ProjectRequestOwner.vue'
import ProjectAcceptReject from '../../../components/Modal/ProjectAcceptReject.vue'
import RejectProjectRequest from '../../../components/Modal/RejectProjectRequest.vue'
import ProjectRequestNotes from '../../../components/Modal/ProjectNotes.vue'
import Schema from '../../Project/ProjectRequest/ProjectRequestSchema'

export default {
    components: { ProjectRequestOwner, ProjectAcceptReject, RejectProjectRequest, ProjectRequestNotes },
    data() {
        return {
            isLoading: false,
            MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [               
                {
                    layoutType: "double",
                    Data: [
                    {
                            astype: "SelectField",                                                
                            label: this.$t('ChooseIndustryType'),
                            name: "IndustryType",
                            value: "",  
                            config: {
                                options: [],
                                onChange: this.GetTemplateListData
                            },                           
                            placeholder: this.$t('Select Industry'),
                            validationRules: { "required": true, max: 100 },
                        },
                        {
                            astype: "SelectField",                                                
                            label: this.$t('SelectTemplate'),
                            name: "selecttemplate",
                            value: "",  
                            visibility:false,
                            config: {
                                options: []
                            },                           
                            placeholder: this.$t('Select Template'),
                            validationRules: { "required": true, max: 100 },
                        }           
                    ]
                }                
            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible:true
                },            
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.CloseProjectConvert,
                },
            ],
            isProjectRequest: false,
            IsProjectAccpt: false,
            IsProjectReject: false,
            IsProjectNotes: false,
            IsRequest: false,
            AcceptRejectData: {},
            widgets: [],
            SortExp: '',
            searchCondition: '',
            LegendArray: [],
            SortExp: '',
            SortBy: '',
            TotalRecords: 0,
            PageNumber: 1,
            PageSize: 10,
            CurrentPage: 1,
            RequestData: [],
            ProjectData: [],
            listheaderbuttons: Schema.buttons,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            Headers: [
                {
                    "COLUMN_NAME": "TITLE",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Title",
                    "DISPLAY_ORDER": 1,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "DESCRIPTION",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Description",
                    "DISPLAY_ORDER": 2,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "COMPANY_NAME",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Company",
                    "DISPLAY_ORDER": 3
                },
                {
                    "COLUMN_NAME": 'BUDGET',
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Budget",
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: true
                    }
                },
                {
                    "COLUMN_NAME": "STATUS_NAME",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": "Status",
                    "DISPLAY_ORDER": 5,
                    settings: {
                        isInSlot: true
                    }
                }],
            CurrencyCode: '',
            EditQuoteDate:'',
            ProjectId:0,
            isShowConvertProject:false,
            RequestId:0,
            Key:0
        }
    },
    created: function () {
        var ths = this;
        ths.CurrencyCode = ths.GetUserInfo.Currency.replace(/[()]/g, '');
        Schema.bindleftCommonSearchdropdown(ths, "ProjectRequest", "Status");
        ths.FetchData();
    },
    methods: {
        CloseProjectAccptReject(){
            var ths=this;
            ths.IsProjectAccpt = false;
            ths.FetchData();
        },
        CloseProjectReject(){
            var ths=this;
            ths.IsProjectReject = false;
            ths.FetchData();
        },
        CloseProjectConvert(){
          this.isShowConvertProject=false;
        }, 
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddProjectRequest":
                    this.AddProjectRequest();
                    break;
                case "AddProjectRequestOwner":
                    this.AddProjectRequestOwner();
                    break;
                case "Accept":
                    this.Accept();
                    break;
                case "Reject":
                    this.Reject();
                    break;
                case "AssignTag":
                    this.AssignTag();
                    break;
                case "commonDeleteData":
                    this.commonDeleteData();
                    break;
            }
        },
        commonDeleteData: function (id) {
            var vm = this;
            var val = "";
            vm.isLoading = true;
            if (id == null) {

                $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                    if (val.length > 0)
                        val += ',';
                    val += $(this).val();
                });
            }
            else {
                val = id;
            }
            if (val != null) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Request")), function () {
                    var postJSON = {
                        ids: val,
                        MODULENAME: "PROJECT",
                        refCode: "PROJECT_REQUEST"
                    };
                    var objectPostString = JSON.stringify(postJSON);
                    DataService.CommonCommonDelete(objectPostString).then(function (response) {
                        vm.isLoading = false;
                        if (response.status == 200) {
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Request')]), "success", true, vm.$t("Alert"));
                            vm.FetchData();
                            vm.Key++;
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Request')]), "Success", true, vm.$t("Alert"));
                        }
                    });
                });
            }
            else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }
            vm.isLoading = false;
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case 'ShowProjectRequestNotes':
                    this.ShowProjectRequestNotes(item)
                    break;
                case 'ViewQuotation':
                    this.ViewQuotation(item);
                    break;
                case 'ConvertToProject':
                    this.ConvertToProject(item.PROJECT_REQUEST_ID);
                    break;
                case 'Accept':
                    this.AcceptProjectRequest(item);
                    break;
                case 'Reject':
                    this.RejectProjectRequest(item);
                    break;
                case 'EditRequest':
                    this.EditRequest(item);
                    break;
                case 'AddQuotation':
                    this.AddQuotation(item);
                    break;
                
            }
        },        
       
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Show Project Request Notes':
                        action.isVisible = true;
                        break;
                    case 'View Quotation':
                        action.isVisible = true;
                        break;
                    case 'Convert To Project':
                        action.isVisible = true;
                        break;
                    case 'Accept':
                        action.isVisible = true;
                        break;
                    case 'Reject':
                        action.isVisible = true;
                        break;
                    case 'Add Quotation':
                        action.isVisible = true;
                        break;
                    case 'Click here to edit Project Request':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                    this.searchCondition = value.searchConditionJson;
                }
            }
            else {
                this.searchCondition = "";
            }
            this.FetchData();
        },
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        FetchData: function () {
            var ths = this;
            if (ths.isBlank(ths.searchCondition)) {
                var url = `sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&totalRecords=&StatusID=&search=`;
            } else {
                var url = `sortBy=${ths.SortBy}&sortExp=${ths.SortExp}&pageSize=${ths.PageSize}&pageNum=${ths.PageNumber}&totalRecords=&status=${ths.Status}&${ths.searchCondition}`;
            }
            DataService.ProjectRequestList(url).then((response)=>{
                if(response.data.result.length>0){ 
                     ths.Headers.forEach((item)=>{
                       if(item.COLUMN_NAME=='BUDGET')
                       {                        
                        var getrcurrencysimble = this.$n(0, 'currency', this.$getLocaleByCurrency(this.CurrencyCode))
                        item.DISPLAY_NAME='Budget ('+ getrcurrencysimble.charAt(0)+')';
                       }
                     });
                    ths.RequestData = response.data.result;                    
                    ths.TotalRecords = response.data.result[0].TOTAL;
                    ths.TotalPages = Math.ceil(ths.TotalRecords / ths.PageSize);
                    ths.CurrentPage = ths.PageNumber;
                } else {
                    ths.RequestData = [];
                }
            })
        },
        Accept: function (e) {
            var vm = this;
            var vall = [];
            var val = '';
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                val = $(this).val();
                let filteredData = vm.RequestData.filter(request => request.PROJECT_REQUEST_ID === parseInt(val));
                debugger
                if (filteredData.length > 0) {
                    filteredData.forEach((item) => {
                        var Obj = {
                            ProjectRequestId: val,
                            CreatedBy: item.CREATED_BY,
                            CreatedByName: item.CREATED_BY_NAME,
                            ProjectTitle: item.TITLE
                        }
                        vall.push(Obj);
                    })
                }
            });
            if (vall.length > 0) {
                vm.confirmR(vm.$t("ProjectRequestUpdateAcceptStatus"), true, (vm.$t("Project")), function () {
                    var data = {
                        ids: vall,
                        type: 'A'
                    };
                    vm.isLoading = true;
                    var objectPostString = JSON.stringify(data);
                    DataService.UpdateProjectRequestStatus(objectPostString).then(function (response) {
                        vm.isLoading = false;
                        if (response.status == 200) {
                            vm.ShowAlert(vm.$t("ProjectRequestAcceptMessage"), "success", true, vm.$t("Alert"));
                            vm.FetchData();
                        } else {
                            vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", true, vm.$t('Alert'));
                        }
                    });
                });
            }
        },
        Reject: function (e) {
            var vm = this;
            var vall = [];
            var val = '';
            $('.chkItems:checkbox:checked').not("[id^='chkAll']").each(function () {
                val = $(this).val();
                let filteredData = vm.RequestData.filter(request => request.PROJECT_REQUEST_ID === parseInt(val));
                if (filteredData.length > 0) {
                    filteredData.forEach((item) => {
                        var Obj = {
                            ProjectRequestId: val,
                            CreatedBy: item.CREATED_BY,
                            CreatedByName: item.CREATED_BY_NAME,
                            ProjectTitle: item.TITLE
                        }
                        vall.push(Obj);
                    })
                }
            });
            if (vall.length > 0) {
                vm.confirmR(vm.$t("ProjectRequestUpdateAcceptStatus"), true, (vm.$t("Project")), function () {
                    var data = {
                        ids: vall,
                        type: 'R'
                    };
                    vm.isLoading = true;
                    var objectPostString = JSON.stringify(data);
                    DataService.UpdateProjectRequestStatus(objectPostString).then(function (response) {
                        vm.isLoading = false;
                        if (response.status == 200) {
                            vm.ShowAlert(vm.$t("ProjectRequestRejectMessage"), "success", true, vm.$t("Alert"));
                            vm.FetchData();
                        } else {
                            vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", true, vm.$t('Alert'));
                        }
                    });
                });
            }
        },
        removeHtmlTags(content) {
            return content.replace(/<[^>]+>/g, '');
        },
        AddProjectRequest() {
            this.$router.push({ name: 'AddProjectRequest' });
        },
        AddProjectRequestOwner: function () {
            this.isProjectRequest = true;
        },
        AcceptProjectRequest: function (itm) {
            var vm = this;
            vm.confirmR(vm.$t("ProjectRequestAcceptConfirmMessage"), true, (vm.$t("Project")), function () {
                var data = {
                    Prid: itm.PROJECT_REQUEST_ID,
                    type: 'A',
                    createdby: itm.CREATED_BY,
                    prtitle: itm.TITLE,
                    createdbyname: itm.CREATED_BY_NAME,
                    convPid: itm.PROJECT_REQUEST_ID
                }
                vm.isLoading = true;
                var objectPostString = JSON.stringify(data);
                DataService.AcceptProjectRequest(objectPostString).then(function (response) {
                    vm.isLoading = false;
                    if (response.data != null) {
                        vm.IsProjectAccpt = true;
                        vm.AcceptRejectData = response.data;
                    } else {
                        vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", true, vm.$t('Alert'));
                    }

                })
            })
        },
        RejectProjectRequest: function (itm) {
            var vm = this;
            vm.confirmR(vm.$t("ProjectRequestConfirmMessage"), true, (vm.$t("Project")), function () {
                var data = {
                    Prid: itm.PROJECT_REQUEST_ID,
                    type: 'R',
                    createdby: itm.CREATED_BY,
                    prtitle: itm.TITLE,
                    createdbyname: itm.CREATED_BY_NAME
                }
                vm.isLoading = true;
                var objectPostString = JSON.stringify(data);
                DataService.RejectProjectRequest(objectPostString).then(function (response) {
                    vm.isLoading = false;
                    if (response.data != null) {
                        vm.IsProjectReject = true;
                        vm.AcceptRejectData = response.data;
                    } else {
                        vm.ShowAlert(vm.$t('ErrorWhileProcessingRequest'), "failure", true, vm.$t('Alert'));
                    }

                })
            })
        },
        ConvertToProject: function (reqId) {
            var vm = this;
            vm.isShowConvertProject=true;
            vm.RequestId=reqId;
            vm.GetIndustryType();            
        },
        GetIndustryType: function () {
            this.isLoading=true;
            this.FormSchema[0].Data[0].config.options=[];
              DataService.GetTemplateList().then((response) => {
                this.isLoading = false;
                if (response.data.result.DATA.length > 0) {
                    response.data.result.DATA.forEach((item) => {
                        var Obj = {
                            name:item.name,
                            value:item.id
                        }
                        this.FormSchema[0].Data[0].config.options.push(Obj);
                    });
                    this.isLoading=false;
                }
                vm.$refs.ConvertProject.UpdateKeyValue();      
            });
        },
        GetTemplateListData: function (evt) {
            var vm = this;
            vm.isLoading = true;
            vm.FormSchema[0].Data[1].visibility=true;
            vm.FormSchema[0].Data[1].config.options=[];
            var url = `IndustryTypeId=${evt.target.value}`;
            DataService.GetTemplateListData(url).then((response) => {
                vm.isLoading = false;
                var result = response.data.result;
                if (result != '' && result != null) {
                   if (result.DATA != null && result.DATA != '' && result.DATA != []) {
                       response.data.result.DATA;
                       response.data.result.DATA.forEach((item) => {
                        var Obj = {
                            name:item.name,
                            value:item.id
                        }
                        vm.FormSchema[0].Data[1].config.options.push(Obj);
                    });
                    }
                        vm.$refs.ConvertProject.UpdateKeyValue();      
                }

            });
        },
        OnSubmit:function(){
            var vm=this;
            var reqId=vm.RequestId;
            var industry_type_id=vm.FormSchema[0].Data[0].value;
            var Template_id=vm.FormSchema[0].Data[1].value;
            var data = { 
                id: reqId,
                templateId:Template_id,
                industrytype_id:industry_type_id
             };
                vm.isLoading = true;
                var objectPostString = JSON.stringify(data);
                DataService.ConvertToProject(objectPostString).then(function (response) {
                    vm.isLoading = false;
                    if (response.data.response == 'success') {
                        vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Project')]), "success", true, vm.$t("Alert"));
                        vm.FetchData();
                        vm.isShowConvertProject=false;
                    }
                    else {
                        vm.ShowAlert(vm.$t("UnknownErrorOccur"), "failure", true, vm.$t('Alert'));
                    }
                })
        },
        ShowProjectRequestNotes: function (itm) {
            var vm = this;            
            var obj = {
                Prid: itm.PROJECT_REQUEST_ID,
                ProjectTitle: itm.TITLE,
                createdby: itm.CREATED_BY,
                type: '',
                createdbyname: itm.CREATED_BY_NAME,
                pstcmnt: 'N'
            }
            vm.AcceptRejectData = obj;
            vm.IsProjectNotes = true;
        },
        EditRequest: function (data) { 
            var vm = this;
            vm.$router.push({ name: 'EditProjectRequest', params: { QuotationId: data.PROJECT_REQUEST_ID } });
            
        },
        ViewQuotation: function (itm) {
            this.$router.push({ name: 'DisplayQuotation', params: {  QuotationId: itm.QUOTATION_ID || 0,Code: 1 } });
        },
        AddQuotation(data){
            this.$router.push({
                name: 'Quotation',
                params: {
                    id: data.PROJECT_REQUEST_ID || 0,
                    code: 1 || '',
                    clientId: data.CREATED_BY || 0,
                    title: data.TITLE || 'N/A',
                    requestFromPop: 0 || 0,
                    currency: vm.CurrencyCode || '',
                    reform: 'ProjectRequest'
                }
            });
        }
    }
}
</script>