<template>
    <div class="my-popups">
        <loader :is-visible="isLoading"></loader>
        <div class="modal d-block">
            <div class="modal-dialog modal-dialog-centered">
                <div class="modal-content">
                    <div class="modal-header theme-primary partition-full  d-flex">
                        <h4 class="modal-title">{{ $t('AcceptProjectRequest') }} </h4>
                        <button type="button" class="close" v-on:click="Close">
                            <em class="fa fa-times" aria-hidden="true"></em>
                        </button>                        
                    </div>
                    <div class="modal-body">
                        <dynamic-form :buttons="buttons" :schema="FormSchema" ref="AcceptRejectForm" :mandatorytext='MandatoryString'
                            v-on:OnSubmit="OnSubmit"></dynamic-form>
                    </div>
                </div>
            </div>
        </div>
    </div>
</template>
<script>
import DataService from '../../services/DataService';
export default{
    props:{
        AcceptRejectData:{
            type:Object,
            required:true
        }
    },
    data(){
       return{
        isLoading:false,
        MandatoryString:'Fields marked with an asterisk (*) are mandatory.',
        FormSchema: [  
                {
                    layoutType: "single",
                    Data: [
                        {
                            astype: "TextAreaField",                 
                            label: this.$t('Description'),
                            name: "Description",
                            value: "",  
                            validationRules: { "required": true, max: 4000 },
                            config: {
                                rows:3
                            }
                        }
                    ]
                }
        ],
        buttons: [
            {
                type: "submit",
                class: "btn btn-success",
                text: "<i class='fa fa-send pr-2'></i>Accept"
            },            
            {
                type: "submit",
                class: "btn btn-primary",
                text: "<i class='fa fa-forward pr-2'></i>Skip",
                onClick: this.btnAcceptSkipProjectRequestComment,
            },
        ]
       }
    },
    created: function(){        
        var ths = this;
    },
    methods:{
        OnSubmit:function(){            
            var vm=this;
            var data = {
                Prid:vm.AcceptRejectData.prid,
                type:vm.AcceptRejectData.type,
                createdby:vm.AcceptRejectData.createdby,
                prtitle:vm.AcceptRejectData.prtitle,
                createdbyname:vm.AcceptRejectData.createdbyname,
                notes:vm.FormSchema[0].Data[0].value
            } 
            vm.isLoading = true; 
            var objectPostString = JSON.stringify(data); 
            DataService.ProjectRequestAccept(objectPostString).then(function (response) { 
                vm.isLoading = false;
                if(response.data.response=='success'){
                    vm.ShowAlert(vm.$t("ProjectRequestAcceptMessage"),"success",true,vm.$t("Alert"));
                    vm.Close();
                    vm.AddConvertToProjectButton();
                }else{
                    vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"),"failure",true,vm.$t("Alert"));
                }                
            })
        },
        btnAcceptSkipProjectRequestComment:function(){            
            var vm=this;
            vm.FormSchema[0].Data[0].validationRules['required']=false;
            var data = {
                Prid:vm.AcceptRejectData.prid,
                type:vm.AcceptRejectData.type,
                createdby:vm.AcceptRejectData.createdby,
                prtitle:vm.AcceptRejectData.prtitle,
                createdbyname:vm.AcceptRejectData.createdbyname,
                notes:vm.FormSchema[0].Data[0].value
            } 
            vm.isLoading = true; 
            var objectPostString = JSON.stringify(data); 
            DataService.ProjectRequestAccept(objectPostString).then(function (response) { 
                vm.isLoading = false;                
                if(response.data.response=='success'){
                    vm.ShowAlert(vm.$t("ProjectRequestAcceptMessage"),"success",true,vm.$t("Alert"));
                    vm.Close();
                    vm.AddConvertToProjectButton();
                }else{
                    vm.ShowAlert(vm.$t("ErrorWhileProcessingRequest"),"failure",true,vm.$t("Alert"));
                }
                
            })

        },
        AddConvertToProjectButton:function(){},
        Close:function(){
            this.$emit('CloseProjectAccptReject');
        }
    }
}
</script>